Here's a minimal API endpoint that handles multipart form uploads with multiple images and a description:

```csharp
using Microsoft.AspNetCore.Http.Features;

var builder = WebApplication.CreateBuilder(args);

// Raise the max request body size to 50 MB
builder.WebHost.ConfigureKestrel(o =>
    o.Limits.MaxRequestBodySize = 50 * 1024 * 1024);

var app = builder.Build();

app.MapPost("/upload", async (HttpRequest request) =>
{
    // Ensure it's a multipart/form-data request
    if (!request.HasFormContentType)
        return Results.BadRequest("Expected a multipart/form-data request.");

    var form = await request.ReadFormAsync();

    var description = form["description"].ToString();
    var files = form.Files.GetFiles("images"); // matches <input name="images" />

    if (files.Count == 0)
        return Results.BadRequest("No image files provided.");

    var saved = new List<string>();

    foreach (var file in files)
    {
        // Validate content type
        if (!file.ContentType.StartsWith("image/"))
            return Results.BadRequest($"'{file.FileName}' is not an image.");

        var destPath = Path.Combine("uploads", $"{Guid.NewGuid()}{Path.GetExtension(file.FileName)}");
        Directory.CreateDirectory("uploads");

        await using var stream = File.Create(destPath);
        await file.CopyToAsync(stream);

        saved.Add(destPath);
    }

    return Results.Ok(new { description, fileCount = saved.Count, paths = saved });
})
.DisableAntiforgery()                      // required for minimal APIs accepting forms
.WithMetadata(new RequestFormLimitsAttribute // per-endpoint form size limit
{
    MultipartBodyLengthLimit = 50 * 1024 * 1024
});

app.Run();
```

**Key points:**

- **Kestrel limit** — `MaxRequestBodySize` caps the entire request; default is ~30 MB.
- **`RequestFormLimitsAttribute`** — sets the per-endpoint multipart body limit (otherwise defaults to ~128 MB but is still gated by Kestrel).
- **`.DisableAntiforgery()`** — required in .NET 8 minimal APIs for form endpoints, otherwise you get a 400.
- **`form.Files.GetFiles("images")`** — binds to the form field name; use `form.Files` to grab all files regardless of name.

A matching `curl` test:

```bash
curl -X POST http://localhost:5000/upload \
  -F "description=My vacation photos" \
  -F "images=@photo1.jpg" \
  -F "images=@photo2.png"
```
